42	      return;
43	    }
44	    const lines = inputText.split("\n").filter(l => l.trim());
45	    const parsed = lines.map(l => {
46	      const parts = l.split("\t");
47	      if (parts.length >= 2) {
48	        return { INCIName: parts[0].trim(), Miktar: (parts[1] || "0").trim().replace(",", ".") };
49	      }
50	      const fb = l.split(/\s\s+/);
51	      if (fb.length >= 2) {
52	        return { INCIName: fb[0].trim(), Miktar: fb[1].trim().replace(",", ".") };
53	      }
54	      return null;
55	    }).filter((x): x is { INCIName: string; Miktar: string } => !!x?.INCIName);
