65	  const handleFile = (e: React.ChangeEvent<HTMLInputElement>) => {
66	    const file = e.target.files?.[0];
67	    if (!file) return;
68	    setError("");
69	    const reader = new FileReader();
70	    reader.onload = evt => {
71	      try {
72	        const bstr = evt.target?.result;
73	        const wb = XLSX.read(bstr, { type: "binary" });
74	        const ws = wb.Sheets[wb.SheetNames[0]];
75	        const data = XLSX.utils.sheet_to_json(ws) as Record<string, unknown>[];
76	        const items = data.map(row => ({
77	          INCIName: String(row["INCI İsmi"] ?? row["INCI ismi"] ?? row["INCI"] ?? "").trim(),
78	          Miktar: String(row["Üst Değer(%)"] ?? row["Üst değer(%)"] ?? row["Miktar"] ?? "0").replace(",", "."),
79	        })).filter(i => i.INCIName);
80	        if (items.length === 0) {
81	          setError("Excel'de 'INCI İsmi' ve 'Üst Değer(%)' (veya Miktar) sütunları bulunamadı.");
82	          return;
83	        }
84	        appendRows(items);
85	      } catch {
86	        setError("Dosya okunamadı.");
87	      }
88	    };
89	    reader.readAsBinaryString(file);
90	    e.target.value = "";
91	  };
