107	        const m = json[i];
108	        if (!m) return r;
109	        return {
110	          ...r,
111	          INCIName: m.INCIName || m.inputName || r.INCIName,
112	          Miktar: m.inputAmount || r.Miktar,
113	        };
114	      });
115	      onChange(next);
116	    } catch (e: unknown) {
117	      setError(e instanceof Error ? e.message : "Hata");
118	    } finally {
119	      setLoading(false);
120	    }
121	  };
122	
123	  const update = (key: string, patch: Partial<FormulRow>) =>
124	    onChange(rows.map(r => (r.key === key ? { ...r, ...patch } : r)));
