131	        Formül kontrol sayfasındaki gibi yapıştırma veya Excel şablonu kullanın. İsterseniz satırları ekledikten sonra
132	        INCI isimlerini veritabanı ile eşleştirin.
133	      </p>
134	
135	      {error && <div className={styles.formError} style={{ marginBottom: 12 }}>{error}</div>}
136	
137	      <div className={styles.formGroup} style={{ marginBottom: 12 }}>
138	        <label>Yapıştır (satır başına: INCI [tab] miktar)</label>
139	        <textarea
140	          rows={5}
141	          style={{ width: "100%", resize: "vertical", fontFamily: "ui-monospace, monospace", fontSize: "0.8rem" }}
142	          value={inputText}
143	          onChange={e => setInputText(e.target.value)}
144	          placeholder={"GLYCERIN\t5\nAQUA\t80"}
145	        />
146	      </div>
147	      <div style={{ display: "flex", gap: 10, flexWrap: "wrap", marginBottom: 20 }}>
148	        <button type="button" className={styles.saveBtn} onClick={handlePaste}>Satırları ekle</button>
149	        <input ref={fileRef} type="file" accept=".xlsx,.xls" style={{ display: "none" }} onChange={handleFile} />
150	        <button type="button" className={styles.cancelBtn} onClick={() => fileRef.current?.click()}>
151	          Excel seç
152	        </button>
153	        <button type="button" className={styles.cancelBtn} onClick={() => void matchAll()} disabled={rows.length === 0 || loading}>
154	          {loading ? "Eşleştiriliyor…" : "Tümünü formül kontrol ile eşleştir"}
155	        </button>
156	      </div>
157	
158	      {rows.length === 0 ? (
159	        <div className={styles.empty} style={{ padding: 24 }}>Formül satırı yok.</div>
160	      ) : (
161	        <div className={styles.tableWrapper}>
162	          <table className={styles.table}>
163	            <thead>
