172	            <tbody>
173	              {rows.map(r => (
174	                <tr key={r.key}>
175	                  <td>
176	                    <input style={{ width: "100%" }} value={r.INCIName} onChange={e => update(r.key, { INCIName: e.target.value })} />
177	                  </td>
178	                  <td>
179	                    <input style={{ width: "100%" }} value={r.Miktar} onChange={e => update(r.key, { Miktar: e.target.value })} />
180	                  </td>
