36	function FirmaSearch({
37	  label, value, displayValue, onChange, placeholder,
38	}: {
39	  label: string;
40	  value: number | null;
41	  displayValue: string;
42	  onChange: (id: number | null, ad: string) => void;
43	  placeholder?: string;
44	}) {
45	  const [q, setQ]           = useState(displayValue);
46	  const [results, setRes]   = useState<{ ID: number; Ad: string }[]>([]);
47	  const [open, setOpen]     = useState(false);
48	  const timer               = useRef<ReturnType<typeof setTimeout> | null>(null);
49	  const wrapRef             = useRef<HTMLDivElement>(null);
50	
51	  useEffect(() => { setQ(displayValue); }, [displayValue]);
52	
53	  useEffect(() => {
54	    const handler = (e: MouseEvent) => {
55	      if (wrapRef.current && !wrapRef.current.contains(e.target as Node)) {
56	        setOpen(false);
57	      }
58	    };
59	    document.addEventListener("mousedown", handler);
60	    return () => document.removeEventListener("mousedown", handler);
61	  }, []);
62	
63	  const search = useCallback((val: string) => {
64	    if (timer.current) clearTimeout(timer.current);
65	    timer.current = setTimeout(async () => {
66	      if (val.trim().length < 1) { setRes([]); setOpen(false); return; }
67	      try {
68	        const r = await fetch(`/api/numune-form/firmalar?q=${encodeURIComponent(val)}`);
69	        const data = await r.json();
70	        setRes(data);
71	        setOpen(data.length > 0);
72	      } catch { setRes([]); }
73	    }, 200);
74	  }, []);
