82	        onChange={e => { setQ(e.target.value); search(e.target.value); if (!e.target.value) onChange(null, ""); }}
83	        onFocus={() => { if (results.length) setOpen(true); }}
84	        autoComplete="off"
85	      />
86	      {value ? (
87	        <button
88	          type="button"
89	          onClick={() => { onChange(null, ""); setQ(""); setRes([]); }}
90	          style={{ position: "absolute", right: 8, top: 28, background: "none", border: "none", cursor: "pointer", color: "var(--color-text-tertiary)", fontSize: "0.8rem" }}
