92	        >✕</button>
93	      ) : null}
94	      {open && results.length > 0 ? (
95	        <div style={{
96	          position: "absolute", zIndex: 300, top: "100%", left: 0, right: 0,
97	          background: "var(--color-surface)", border: "1px solid var(--color-border)",
98	          borderRadius: "var(--radius-sm)", boxShadow: "0 4px 16px rgba(0,0,0,0.12)",
99	          maxHeight: 200, overflowY: "auto",
100	        }}>
