26	function dat(v: unknown): string {
27	  if (v == null || v === "") return "";
28	  const s = String(v);
29	  return s.includes("T") ? s.split("T")[0]! : s.slice(0, 10);
30	}
31	
32	function d(v: unknown): string {
33	  return v == null ? "" : String(v);
34	}
35	
36	function di(v: unknown): number | null {
37	  if (v == null || v === "") return null;
38	  const n = Number(v);
39	  return Number.isFinite(n) ? n : null;
40	}
41	
42	function normalizePartialDate(v: string): string | null {
43	  if (!v) return null;
44	  const parts = v.split("-");
45	  if (parts.length === 1) return `${parts[0]}-01-01`;     // year only
46	  if (parts.length === 2) return `${parts[0]}-${parts[1]}-01`; // year+month
47	  return v; // full date
48	}
