function newKey() {
  return `f-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
}

interface Props {
  rows: FormulRow[];
  onChange: (rows: FormulRow[]) => void;
  form: Pick<NkrFormData, "Urun_Tipi" | "Hedef_Grup" | "UGDTip_ID" | "UGDTip_Kategori">;
  onFormChange: (u: Partial<NkrFormData>) => void;
