// ── Mini hizmet panel ──────────────────────────────────────
function HizmetPanel({ tarih, rows, onChange }: { tarih: string; rows: HizmetRow[]; onChange: (r: HizmetRow[]) => void }) {
  const [q, setQ] = useState("");
  const [opts, setOpts] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [open, setOpen] = useState(false);
  const timer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const search = (val: string) => {
    setQ(val);
    if (timer.current) clearTimeout(timer.current);
    timer.current = setTimeout(async () => {
      setLoading(true);
      try {
        const r = await fetch(`/api/teklifler/lookup?type=hizmetler&q=${encodeURIComponent(val)}`);
        const j = await r.json();
        setOpts(j.data || []);
        setOpen(true);
      } finally { setLoading(false); }
    }, 300);
  };

  const addHizmet = (h: any) => {
    if (rows.some(x => x.AnalizID === h.ID)) return;
    const base = tarih ? new Date(tarih + "T12:00:00") : new Date();
    base.setDate(base.getDate() + (h.Sure ?? 0));
    const termin = base.toISOString().split("T")[0]!;
    onChange([...rows, { key: newHizmetKey(), AnalizID: h.ID, Termin: termin, x3ID: null, Kod: h.Kod, Ad: h.Ad, Metot: h.Metot ?? "", Sure: h.Sure ?? null }]);
    setQ(""); setOpts([]); setOpen(false);
  };

  const remove = (key: string) => onChange(rows.filter(r => r.key !== key));

  return (
    <div className={yn.hizmetSection}>
      <div className={yn.hizmetSectionTitle}>Hizmetler</div>
      <div style={{ position: "relative", marginBottom: 8 }}>
        <input
          value={q}
          onChange={e => search(e.target.value)}
          placeholder="Hizmet adı veya kodu…"
          style={{ width: "100%", padding: "6px 10px", border: "1px solid var(--color-border)", borderRadius: "var(--radius-sm)", fontSize: "0.8125rem", background: "var(--color-surface)", color: "var(--color-text-primary)", boxSizing: "border-box" }}
        />
        {open && opts.length > 0 && (
          <div style={{ position: "absolute", top: "100%", left: 0, right: 0, zIndex: 200, background: "var(--color-surface)", border: "1px solid var(--color-border)", borderRadius: "var(--radius-sm)", boxShadow: "0 4px 12px rgba(0,0,0,0.1)", maxHeight: 180, overflowY: "auto" }}>
            {loading ? <div style={{ padding: "8px 12px", fontSize: "0.8rem", color: "var(--color-text-tertiary)" }}>Yükleniyor…</div> : opts.map(h => (
              <div key={h.ID}
                style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "7px 12px", cursor: "pointer", fontSize: "0.8125rem", borderBottom: "1px solid var(--color-border-light)" }}
                onMouseDown={() => addHizmet(h)}
                onMouseEnter={e => (e.currentTarget.style.background = "var(--color-surface-2)")}
                onMouseLeave={e => (e.currentTarget.style.background = "transparent")}
              >
                <span><strong style={{ color: "var(--color-text-tertiary)", marginRight: 6 }}>{h.Kod}</strong>{h.Ad}</span>
                <span style={{ fontSize: "0.75rem", color: "var(--color-text-tertiary)", marginLeft: 8, flexShrink: 0 }}>{h.Sure ? `${h.Sure} g` : ""}</span>
              </div>
            ))}
          </div>
        )}
      </div>
      {rows.length > 0 && (
        <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.8rem" }}>
          <thead>
            <tr style={{ borderBottom: "1px solid var(--color-border-light)" }}>
              <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 600, color: "var(--color-text-secondary)", fontSize: "0.72rem", textTransform: "uppercase" }}>Kod</th>
              <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 600, color: "var(--color-text-secondary)", fontSize: "0.72rem", textTransform: "uppercase" }}>Hizmet</th>
              <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 600, color: "var(--color-text-secondary)", fontSize: "0.72rem", textTransform: "uppercase", width: 140 }}>Termin</th>
              <th style={{ width: 32 }} />
            </tr>
          </thead>
          <tbody>
            {rows.map(r => (
              <tr key={r.key} style={{ borderBottom: "1px solid var(--color-border-light)" }}>
                <td style={{ padding: "5px 8px", color: "var(--color-text-tertiary)", fontVariantNumeric: "tabular-nums" }}>{r.Kod}</td>
                <td style={{ padding: "5px 8px" }}>{r.Ad}</td>
                <td style={{ padding: "5px 8px" }}>
                  <input type="date" value={r.Termin?.slice(0,10) || ""} onChange={e => onChange(rows.map(x => x.key === r.key ? {...x, Termin: e.target.value} : x))} style={{ width: "100%", padding: "3px 6px", border: "1px solid var(--color-border)", borderRadius: 4, fontSize: "0.8rem", background: "var(--color-surface)" }} />
                </td>
                <td style={{ padding: "5px 4px" }}>
                  <button type="button" onClick={() => remove(r.key)} style={{ background: "none", border: "none", cursor: "pointer", color: "var(--color-text-tertiary)", fontSize: "0.85rem", padding: 2 }}>✕</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

